let raw;
if ($json.text) raw = $json.text;
else if ($json.output_text) raw = $json.output_text;
else if ($json.content && Array.isArray($json.content)) raw = $json.content.map(c => c.text || '').join('');
else if ($json.message && $json.message.content && $json.message.content[0]) raw = $json.message.content[0].text;
else raw = JSON.stringify($json);
let cleaned = String(raw).trim();
const fence = cleaned.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
if (fence) cleaned = fence[1].trim();
const start = cleaned.indexOf('{');
const end = cleaned.lastIndexOf('}');
if (start !== -1 && end !== -1) cleaned = cleaned.slice(start, end + 1);
let parsed;
try { parsed = JSON.parse(cleaned); }
catch (e) {
  parsed = { title: 'Note (parsing échoué)', summary: String(raw).slice(0, 280), key_points: [], action_items: [], tags: ['parse-error'], category: 'Autre', content_md: String(raw) };
}
const trigger_data = $('Reception du brouillon').item.json.body || {};
return { json: {
  title: parsed.title || 'Note sans titre',
  summary: parsed.summary || '',
  key_points: Array.isArray(parsed.key_points) ? parsed.key_points : [],
  action_items: Array.isArray(parsed.action_items) ? parsed.action_items : [],
  tags: Array.isArray(parsed.tags) ? parsed.tags.slice(0, 5) : [],
  category: parsed.category || 'Autre',
  content_md: parsed.content_md || '',
  source: trigger_data.source || 'webhook',
  created_at: new Date().toISOString(),
} };

const data = $json;
function rt(text) { return [{ type: 'text', text: { content: String(text == null ? '' : text) } }]; }
function paragraph(text) { return { object: 'block', type: 'paragraph', paragraph: { rich_text: rt(text) } }; }
function heading(text, level) {
  const key = level === 1 ? 'heading_1' : level === 3 ? 'heading_3' : 'heading_2';
  return { object: 'block', type: key, [key]: { rich_text: rt(text) } };
}
function bullet(text) { return { object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: rt(text) } }; }
function todo(text) { return { object: 'block', type: 'to_do', to_do: { rich_text: rt(text), checked: false } }; }
function divider() { return { object: 'block', type: 'divider', divider: {} }; }
function callout(text, emoji) {
  return { object: 'block', type: 'callout', callout: { rich_text: rt(text), icon: { type: 'emoji', emoji: emoji || '💡' } } };
}
const blocks = [];
if (data.summary) { blocks.push(callout(data.summary, '📝')); blocks.push(divider()); }
if (Array.isArray(data.key_points) && data.key_points.length) {
  blocks.push(heading('Points clés', 2));
  for (const p of data.key_points) blocks.push(bullet(p));
}
if (Array.isArray(data.action_items) && data.action_items.length) {
  blocks.push(heading('Actions à mener', 2));
  for (const a of data.action_items) blocks.push(todo(a));
}
if (data.content_md) {
  blocks.push(divider());
  blocks.push(heading('Détails', 2));
  const lines = String(data.content_md).split(/\r?\n/);
  for (const raw of lines) {
    const line = raw.trim();
    if (!line) continue;
    if (line.startsWith('### ')) blocks.push(heading(line.slice(4), 3));
    else if (line.startsWith('## ')) blocks.push(heading(line.slice(3), 2));
    else if (line.startsWith('# ')) blocks.push(heading(line.slice(2), 1));
    else if (line.startsWith('- [ ] ') || line.startsWith('* [ ] ')) blocks.push(todo(line.slice(6)));
    else if (line.startsWith('- ') || line.startsWith('* ')) blocks.push(bullet(line.slice(2)));
    else blocks.push(paragraph(line));
  }
}
const validCategories = ['Réunion', 'Idée', 'Tâche', 'Recherche', 'Personnel', 'Autre'];
const category = validCategories.indexOf(data.category) !== -1 ? data.category : 'Autre';
const tags = Array.isArray(data.tags) ? data.tags.filter(t => t && typeof t === 'string').slice(0, 10) : [];
return { json: { ...data, category, tags, notion_children: blocks.slice(0, 100) } };
